  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { Link } from 'react-router-dom';
  3→import { CreditPacks } from '../components/settings/credit-packs';
  4→import { SectorTargetingSelector } from '../components/shared/sector-targeting-selector';
  5→import { useAuth } from '../hooks/useAuth';
  6→import { CREDIT_PACKS } from '../lib/constants';
  7→import { isSupabaseConfigured, supabase } from '../lib/supabase';
  8→import type { ApproachTone, CreditPackId, Profile } from '../lib/types';
  9→import { buildProfileSectorPatch, getProfileSectorTargets } from '../utils/sector-targeting';
 10→import { debounce } from '../utils/debounce';
 11→
 12→const TONE_PREVIEWS: Record<ApproachTone, string> = {
 13→  professional: 'Approche structuree, orientee resultat et claire.',
 14→  friendly: 'Approche plus chaleureuse et conversationnelle.',
 15→  direct: 'Approche courte, rapide et orientee action.',
 16→};
 17→
 18→interface ScanNowResponse {
 19→  job_id?: string;
 20→  triggered_sources?: number;
 21→  failed_sources?: number;
 22→  fallback_direct_ingest?: number;
 23→  used_n8n?: boolean;
 24→}
 25→
 26→/**
 27→ * Configuration utilisateur simplifiee.
 28→ */
 29→const SettingsPage = (): JSX.Element => {
 30→  const { profile, patchProfile, refreshProfile } = useAuth();
 31→  const [draft, setDraft] = useState<Profile | null>(profile);
 32→  const [error, setError] = useState<string | null>(null);
 33→  const [status, setStatus] = useState<string>('');
 34→  const [scanLoading, setScanLoading] = useState<boolean>(false);
 35→  const [scanFeedback, setScanFeedback] = useState<string>('');
 36→  const [scanError, setScanError] = useState<string | null>(null);
 37→  const [locationModalOpen, setLocationModalOpen] = useState<boolean>(false);
 38→  const [locationDraft, setLocationDraft] = useState<string>('');
 39→  const [radiusDraft, setRadiusDraft] = useState<number>(30);
 40→
 41→  useEffect(() => {
 42→    setDraft(profile);
 43→  }, [profile]);
 44→
 45→  const savePatch = useCallback(
 46→    async (patch: Partial<Profile>): Promise<void> => {
 47→      if (!profile) {
 48→        return;
 49→      }
 50→      setStatus('Sauvegarde...');
 51→      const ok = await patchProfile(patch);
 52→      if (!ok) {
 53→        setError('Erreur de sauvegarde.');
 54→        setStatus('');
 55→        return;
 56→      }
 57→      setError(null);
 58→      setStatus('Sauvegarde');
 59→      window.setTimeout(() => setStatus(''), 900);
 60→    },
 61→    [patchProfile, profile],
 62→  );
 63→
 64→  const debouncedSave = useMemo(
 65→    () =>
 66→      debounce((patch: Partial<Profile>) => {
 67→        void savePatch(patch);
 68→      }, 500),
 69→    [savePatch],
 70→  );
 71→
 72→  if (!draft || !profile) {
 73→    return (
 74→      <div className="px-4 md:px-0">
 75→        <div className="h-24 animate-pulse rounded-2xl border border-leadradar-border bg-leadradar-card" />
 76→      </div>
 77→    );
 78→  }
 79→
 80→  const creditsBalance = Number(draft.credits_balance ?? 0);
 81→  const creditsSpent = Number(draft.credits_total_spent ?? 0);
 82→  const creditsPurchased = Number(draft.credits_total_purchased ?? 0);
 83→  const creditCostPerLead = Math.max(1, Number(draft.credit_cost_per_prospect ?? 1));
 84→  const autoRechargeThreshold = Math.max(0, Number(draft.auto_recharge_trigger_threshold ?? 3));
 85→  const autoRechargeMaxMonth = Math.max(1, Number(draft.auto_recharge_max_per_month ?? 3));
 86→  const autoRechargeCountMonth = Math.max(0, Number(draft.auto_recharge_count_month ?? 0));
 87→  const automationMinScore = Math.max(0, Math.min(100, Number(draft.automation_min_score ?? 80)));
 88→  const automationDailyLimit = Math.max(1, Number(draft.automation_daily_email_limit ?? 5));
 89→  const sectorTargets = getProfileSectorTargets(draft);
 90→
 91→  const consumptionPercent = Math.min(100, (creditsSpent / Math.max(1, creditsPurchased)) * 100);
 92→  const estimLeadsRemaining = Math.floor(creditsBalance / creditCostPerLead);
 93→
 94→  const runManualScan = useCallback(async (): Promise<void> => {
 95→    if (!profile) {
 96→      return;
 97→    }
 98→
 99→    setScanLoading(true);
100→    setScanError(null);
101→    setScanFeedback('');
102→
103→    try {
104→      if (!isSupabaseConfigured) {
105→        throw new Error('Supabase non configure. Ajoutez VITE_SUPABASE_URL et VITE_SUPABASE_ANON_KEY pour lancer un scan reel.');
106→      }
107→
108→      const { data, error: invokeError } = await supabase.functions.invoke('scan-now', {
109→        body: {
110→          user_id: profile.id,
111→          max_sources: 12,
112→        },
113→      });
114→
115→      if (invokeError) {
116→        throw invokeError;
117→      }
118→
119→      const response = (data ?? {}) as ScanNowResponse;
120→      const triggered = Math.max(0, Number(response.triggered_sources ?? 0));
121→      const failed = Math.max(0, Number(response.failed_sources ?? 0));
122→      const fallback = Math.max(0, Number(response.fallback_direct_ingest ?? 0));
123→
124→      const parts = [`Scan lance sur ${triggered} source(s)`];
125→      if (failed > 0) {
126→        parts.push(`${failed} en echec`);
127→      }
128→      if (fallback > 0) {
129→        parts.push(`${fallback} via pipeline direct`);
130→      }
131→      setScanFeedback(parts.join(' | '));
132→      await refreshProfile();
133→    } catch (caughtError) {
134→      const message = caughtError instanceof Error ? caughtError.message : 'Lancement du scan impossible';
135→      setScanError(message);
136→    } finally {
137→      setScanLoading(false);
138→    }
139→  }, [profile, refreshProfile]);
140→
141→  return (
142→    <div className="space-y-6 px-4 pb-24 md:max-w-6xl md:px-0 md:pb-0">
143→      <header className="flex flex-wrap items-end justify-between gap-3">
144→        <div>
145→          <h1 className="font-outfit text-3xl font-semibold tracking-tight">Configuration</h1>
146→          <p className="mt-1 text-sm text-slate-300">Recharge, ciblage, automatisation. Simple et fluide.</p>
147→        </div>
148→        {status ? <span className="rounded-full bg-emerald-500/15 px-3 py-1 text-xs text-emerald-300">{status}</span> : null}
149→      </header>
150→
151→      {error ? <div className="rounded-xl border border-red-500/40 bg-red-500/10 p-3 text-sm text-red-300">{error}</div> : null}
152→
153→      <section className="grid gap-4 xl:grid-cols-2">
154→        <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
155→          <h2 className="font-outfit text-lg font-semibold">1. Recharge credits</h2>
156→          <p className="mt-3 text-sm text-slate-300">Solde: {creditsBalance} credits</p>
157→          <p className="text-sm text-slate-300">Cout par fiche: {creditCostPerLead} credit</p>
158→          <p className="text-sm text-slate-300">Fiches disponibles maintenant: {estimLeadsRemaining}</p>
159→          <p className="mt-1 text-xs text-slate-400">
160→            Consommes: {creditsSpent} | Achetes: {creditsPurchased}
161→          </p>
162→          <div className="mt-3 h-2 w-full rounded-full bg-slate-800">
163→            <div className="h-full rounded-full bg-emerald-500" style={{ width: `${consumptionPercent}%` }} />
164→          </div>
165→          <button
166→            type="button"
167→            onClick={() => {
168→              if (!isSupabaseConfigured) {
169→                setError('Mode demo: portail Stripe indisponible sans configuration Supabase.');
170→                return;
171→              }
172→              void supabase.functions.invoke('customer-portal', { body: { user_id: profile.id } }).then(({ data }) => {
173→                const url = String((data as { url?: string } | null)?.url ?? '');
174→                if (url) {
175→                  window.location.href = url;
176→                }
177→              });
178→            }}
179→            className="mt-4 rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
180→          >
181→            Historique paiements (Stripe)
182→          </button>
183→          <div className="mt-4">
184→            <CreditPacks userId={profile.id} />
185→          </div>
186→        </article>
187→
188→        <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
189→          <h2 className="font-outfit text-lg font-semibold">2. Auto-recharge</h2>
190→          <p className="mt-1 text-sm text-slate-300">
191→            Recharge automatique declenchee quand le solde passe sous un seuil.
192→          </p>
193→          <div className="mt-4 space-y-3">
194→            <label className="flex items-center justify-between text-sm">
195→              Activer auto-recharge
196→              <input
197→                type="checkbox"
198→                checked={Boolean(draft.auto_recharge_enabled)}
199→                onChange={(event) => {
200→                  const value = event.target.checked;
201→                  setDraft((current) => (current ? { ...current, auto_recharge_enabled: value } : current));
202→                  debouncedSave({ auto_recharge_enabled: value });
203→                }}
204→              />
205→            </label>
206→
207→            <label className="block text-sm text-slate-300">
208→              Pack utilise
209→              <select
210→                value={(draft.auto_recharge_pack_id ?? 'pack_50') as CreditPackId}
211→                onChange={(event) => {
212→                  const value = event.target.value as CreditPackId;
213→                  setDraft((current) => (current ? { ...current, auto_recharge_pack_id: value } : current));
214→                  debouncedSave({ auto_recharge_pack_id: value });
215→                }}
216→                className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
217→              >
218→                {CREDIT_PACKS.map((pack) => (
219→                  <option key={pack.id} value={pack.id}>
220→                    {pack.label} ({pack.credits + pack.bonusCredits} credits)
221→                  </option>
222→                ))}
223→              </select>
224→            </label>
225→
226→            <label className="block text-sm text-slate-300">
227→              Seuil de declenchement: {autoRechargeThreshold} credit(s)
228→              <input
229→                type="range"
230→                min="1"
231→                max="30"
232→                value={autoRechargeThreshold}
233→                onChange={(event) => {
234→                  const value = Number(event.target.value);
235→                  setDraft((current) => (current ? { ...current, auto_recharge_trigger_threshold: value } : current));
236→                  debouncedSave({ auto_recharge_trigger_threshold: value });
237→                }}
238→                className="mt-2 w-full"
239→              />
240→            </label>
241→
242→            <label className="block text-sm text-slate-300">
243→              Limite auto-recharges / mois
244→              <input
245→                type="number"
246→                min="1"
247→                max="20"
248→                value={autoRechargeMaxMonth}
249→                onChange={(event) => {
250→                  const value = Math.max(1, Math.min(20, Number(event.target.value) || 1));
251→                  setDraft((current) => (current ? { ...current, auto_recharge_max_per_month: value } : current));
252→                  debouncedSave({ auto_recharge_max_per_month: value });
253→                }}
254→                className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
255→              />
256→            </label>
257→
258→            <p className="text-xs text-slate-400">
259→              Deja utilises ce mois: {autoRechargeCountMonth} / {autoRechargeMaxMonth}
260→            </p>
261→          </div>
262→        </article>
263→      </section>
264→
265→      <section className="grid gap-4 xl:grid-cols-2">
266→        <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
267→          <h2 className="font-outfit text-lg font-semibold">3. Ciblage recherche</h2>
268→          <p className="mt-3 text-sm text-slate-300">
269→            Secteurs cibles: {sectorTargets.length > 0 ? `${sectorTargets.length} selection(s)` : 'non defini'}
270→          </p>
271→          <div className="mt-3">
272→            <SectorTargetingSelector
273→              value={sectorTargets}
274→              onChange={(nextTargets) => {
275→                const patch = buildProfileSectorPatch(draft, nextTargets);
276→                setDraft((current) => (current ? { ...current, ...patch } : current));
277→                debouncedSave(patch);
278→              }}
279→              maxSelections={25}
280→            />
281→          </div>
282→          <div className="mt-3 flex flex-wrap items-center gap-2">
283→            <button
284→              type="button"
285→              disabled={scanLoading || sectorTargets.length === 0}
286→              onClick={() => {
287→                void runManualScan();
288→              }}
289→              className="rounded-lg bg-emerald-500 px-3 py-2 text-sm font-semibold text-emerald-950 transition hover:bg-emerald-400 disabled:cursor-not-allowed disabled:opacity-60"
290→            >
291→              {scanLoading ? 'Scan en cours...' : 'Scanner maintenant'}
292→            </button>
293→            <p className="text-xs text-slate-400">Declenche un scan immediat des sources actives pour vos secteurs.</p>
294→          </div>
295→          {scanFeedback ? <p className="mt-2 text-xs text-emerald-300">{scanFeedback}</p> : null}
296→          {scanError ? <p className="mt-2 text-xs text-red-300">{scanError}</p> : null}
297→          <p className="text-sm text-slate-300">
298→            Zone: {draft.location_label ?? 'Aucune ville'} | Rayon: {draft.geo_radius_km} km
299→          </p>
300→          <button
301→            type="button"
302→            onClick={() => {
303→              setLocationDraft(draft.location_label ?? '');
304→              setRadiusDraft(draft.geo_radius_km);
305→              setLocationModalOpen(true);
306→            }}
307→            className="mt-3 rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
308→          >
309→            Modifier la zone
310→          </button>
311→
312→          <div className="mt-4">
313→            <label className="text-sm text-slate-300">Score minimum: {draft.min_score}/100</label>
314→            <input
315→              type="range"
316→              min="0"
317→              max="100"
318→              value={draft.min_score}
319→              onChange={(event) => {
320→                const value = Number(event.target.value);
321→                setDraft((current) => (current ? { ...current, min_score: value } : current));
322→                debouncedSave({ min_score: value });
323→              }}
324→              className="mt-2 w-full"
325→            />
326→          </div>
327→          <Link
328→            to="/sources"
329→            className="mt-3 inline-flex rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
330→          >
331→            Ajuster les sources
332→          </Link>
333→        </article>
334→
335→        <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
336→          <h2 className="font-outfit text-lg font-semibold">4. Automatisation prospection</h2>
337→          <p className="mt-1 text-sm text-slate-300">
338→            Sur prospects eligibles et credits disponibles, l app peut envoyer un email automatiquement.
339→          </p>
340→          <div className="mt-4 space-y-3">
341→            <label className="flex items-center justify-between text-sm">
342→              Activer automatisation
343→              <input
344→                type="checkbox"
345→                checked={Boolean(draft.automation_enabled)}
346→                onChange={(event) => {
347→                  const value = event.target.checked;
348→                  setDraft((current) => (current ? { ...current, automation_enabled: value } : current));
349→                  debouncedSave({ automation_enabled: value });
350→                }}
351→              />
352→            </label>
353→
354→            <label className="flex items-center justify-between text-sm">
355→              Envoyer email prospect automatiquement
356→              <input
357→                type="checkbox"
358→                checked={Boolean(draft.automation_send_email)}
359→                onChange={(event) => {
360→                  const value = event.target.checked;
361→                  setDraft((current) => (current ? { ...current, automation_send_email: value } : current));
362→                  debouncedSave({ automation_send_email: value });
363→                }}
364→              />
365→            </label>
366→
367→            <label className="block text-sm text-slate-300">
368→              Score minimum automatisation: {automationMinScore}
369→              <input
370→                type="range"
371→                min="50"
372→                max="100"
373→                value={automationMinScore}
374→                onChange={(event) => {
375→                  const value = Number(event.target.value);
376→                  setDraft((current) => (current ? { ...current, automation_min_score: value } : current));
377→                  debouncedSave({ automation_min_score: value });
378→                }}
379→                className="mt-2 w-full"
380→              />
381→            </label>
382→
383→            <label className="block text-sm text-slate-300">
384→              Limite d emails auto / jour
385→              <input
386→                type="number"
387→                min="1"
388→                max="100"
389→                value={automationDailyLimit}
390→                onChange={(event) => {
391→                  const value = Math.max(1, Math.min(100, Number(event.target.value) || 1));
392→                  setDraft((current) => (current ? { ...current, automation_daily_email_limit: value } : current));
393→                  debouncedSave({ automation_daily_email_limit: value });
394→                }}
395→                className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
396→              />
397→            </label>
398→
399→            <label className="block text-sm text-slate-300">
400→              Sujet email auto
401→              <input
402→                type="text"
403→                value={draft.automation_email_subject_template ?? ''}
404→                onChange={(event) => {
405→                  const value = event.target.value.slice(0, 160);
406→                  setDraft((current) => (current ? { ...current, automation_email_subject_template: value } : current));
407→                  debouncedSave({ automation_email_subject_template: value });
408→                }}
409→                className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
410→                placeholder="Ex: Opportunite detectee pour {{prospect_name}}"
411→              />
412→            </label>
413→
414→            <label className="block text-sm text-slate-300">
415→              Signature email auto
416→              <textarea
417→                value={draft.automation_email_signature ?? ''}
418→                onChange={(event) => {
419→                  const value = event.target.value.slice(0, 600);
420→                  setDraft((current) => (current ? { ...current, automation_email_signature: value } : current));
421→                  debouncedSave({ automation_email_signature: value });
422→                }}
423→                rows={3}
424→                className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
425→                placeholder="Ex: Bien cordialement, ..."
426→              />
427→            </label>
428→
429→            <p className="text-xs text-slate-400">
430→              Envoyes aujourd hui: {Math.max(0, Number(draft.automation_emails_sent_today ?? 0))} / {automationDailyLimit}
431→            </p>
432→          </div>
433→        </article>
434→      </section>
435→
436→      <section className="grid gap-4 xl:grid-cols-2">
437→        <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
438→          <h2 className="font-outfit text-lg font-semibold">5. Alertes</h2>
439→          <div className="mt-3 space-y-2 text-sm">
440→            <label className="flex items-center justify-between">
441→              Email
442→              <input
443→                type="checkbox"
444→                checked={draft.notification_email}
445→                onChange={(event) => {
446→                  const value = event.target.checked;
447→                  setDraft((current) => (current ? { ...current, notification_email: value } : current));
448→                  debouncedSave({ notification_email: value });
449→                }}
450→              />
451→            </label>
452→            <label className="flex items-center justify-between">
453→              Push
454→              <input
455→                type="checkbox"
456→                checked={draft.notification_push}
457→                onChange={(event) => {
458→                  const value = event.target.checked;
459→                  setDraft((current) => (current ? { ...current, notification_push: value } : current));
460→                  debouncedSave({ notification_push: value });
461→                }}
462→              />
463→            </label>
464→            <label className="flex items-center justify-between">
465→              Brulants uniquement
466→              <input
467→                type="checkbox"
468→                checked={draft.burning_only_alerts}
469→                onChange={(event) => {
470→                  const value = event.target.checked;
471→                  setDraft((current) => (current ? { ...current, burning_only_alerts: value } : current));
472→                  debouncedSave({ burning_only_alerts: value });
473→                }}
474→              />
475→            </label>
476→          </div>
477→        </article>
478→
479→        <details className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
480→          <summary className="cursor-pointer font-outfit text-lg font-semibold">6. Parametres avances</summary>
481→          <div className="mt-4 space-y-4">
482→            <div>
483→              <label className="text-sm text-slate-300">Frequence de scan</label>
484→              <select
485→                value={draft.scan_frequency_hours}
486→                onChange={(event) => {
487→                  const value = Number(event.target.value);
488→                  setDraft((current) => (current ? { ...current, scan_frequency_hours: value } : current));
489→                  debouncedSave({ scan_frequency_hours: value });
490→                }}
491→                className="mt-2 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
492→              >
493→                <option value={2}>Toutes les 2h</option>
494→                <option value={6}>Toutes les 6h</option>
495→                <option value={12}>Toutes les 12h</option>
496→                <option value={24}>Toutes les 24h</option>
497→              </select>
498→            </div>
499→
500→            <div>
501→              <label className="text-sm text-slate-300">Ton des messages</label>
502→              <div className="mt-2 grid gap-2 md:grid-cols-3">
503→                {([
504→                  ['professional', 'Professionnel'],
505→                  ['friendly', 'Amical'],
506→                  ['direct', 'Direct'],
507→                ] as Array<[ApproachTone, string]>).map(([tone, label]) => (
508→                  <label
509→                    key={tone}
510→                    className={`rounded-lg border p-3 text-sm ${
511→                      draft.approach_tone === tone ? 'border-emerald-500 bg-emerald-500/10' : 'border-leadradar-border bg-[#0F172A]'
512→                    }`}
513→                  >
514→                    <input
515→                      type="radio"
516→                      name="approach-tone"
517→                      checked={draft.approach_tone === tone}
518→                      onChange={() => {
519→                        setDraft((current) => (current ? { ...current, approach_tone: tone } : current));
520→                        debouncedSave({ approach_tone: tone });
521→                      }}
522→                      className="mr-2"
523→                    />
524→                    {label}
525→                    <p className="mt-2 text-xs text-slate-300">{TONE_PREVIEWS[tone]}</p>
526→                  </label>
527→                ))}
528→              </div>
529→            </div>
530→          </div>
531→        </details>
532→      </section>
533→
534→      {locationModalOpen ? (
535→        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
536→          <div className="w-full max-w-md rounded-2xl border border-leadradar-border bg-[#111827] p-5">
537→            <h3 className="font-outfit text-lg font-semibold">Zone geographique</h3>
538→            <label className="mt-3 block text-sm">
