import { useCallback, useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import { CreditPacks } from '../components/settings/credit-packs';
import { SectorTargetingSelector } from '../components/shared/sector-targeting-selector';
import { useAuth } from '../hooks/useAuth';
import { CREDIT_PACKS } from '../lib/constants';
import { isSupabaseConfigured, supabase } from '../lib/supabase';
import type { ApproachTone, CreditPackId, Profile } from '../lib/types';
import { buildProfileSectorPatch, getProfileSectorTargets } from '../utils/sector-targeting';
import { debounce } from '../utils/debounce';
import {
  Settings,
  Paintbrush,
  Image,
  Building2,
  Palette,
  FileDown,
  Globe,
  Save,
  Check,
  Crown,
  Eye,
} from 'lucide-react';
import { jsPDF } from 'jspdf';

const TONE_PREVIEWS: Record<ApproachTone, string> = {
  professional: 'Approche structuree, orientee resultat et claire.',
  friendly: 'Approche plus chaleureuse et conversationnelle.',
  direct: 'Approche courte, rapide et orientee action.',
};

interface ScanNowResponse {
  job_id?: string;
  triggered_sources?: number;
  failed_sources?: number;
  fallback_direct_ingest?: number;
  used_n8n?: boolean;
}

interface WhiteLabelSettings {
  logoUrl: string;
  agencyName: string;
  primaryColor: string;
  secondaryColor: string;
}

const WL_STORAGE_KEY = 'citedby-whitelabel';

const loadWhiteLabelSettings = (): WhiteLabelSettings => {
  try {
    const raw = window.localStorage.getItem(WL_STORAGE_KEY);
    if (raw) {
      return JSON.parse(raw) as WhiteLabelSettings;
    }
  } catch {
    // ignore parse errors
  }
  return {
    logoUrl: '',
    agencyName: '',
    primaryColor: '#a855f7',
    secondaryColor: '#7c3aed',
  };
};

const saveWhiteLabelSettings = (settings: WhiteLabelSettings): void => {
  window.localStorage.setItem(WL_STORAGE_KEY, JSON.stringify(settings));
};

/**
 * Hex color to RGB helper for jsPDF.
 */
const hexToRgb = (hex: string): [number, number, number] => {
  const clean = hex.replace('#', '');
  const r = parseInt(clean.substring(0, 2), 16) || 0;
  const g = parseInt(clean.substring(2, 4), 16) || 0;
  const b = parseInt(clean.substring(4, 6), 16) || 0;
  return [r, g, b];
};

/**
 * Generate branded PDF report.
 */
const generateBrandedPdf = (wl: WhiteLabelSettings): void => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();

  // Header bar with primary color
  const [pr, pg, pb] = hexToRgb(wl.primaryColor);
  doc.setFillColor(pr, pg, pb);
  doc.rect(0, 0, pageWidth, 40, 'F');

  // Agency name in header
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text(wl.agencyName || 'Agence', 15, 18);

  // Subtitle
  doc.setFontSize(11);
  doc.setFont('helvetica', 'normal');
  doc.text('Rapport de performance - White Label', 15, 28);

  // Date
  doc.setFontSize(9);
  doc.text(`Genere le ${new Date().toLocaleDateString('fr-FR')}`, 15, 35);

  // Secondary color accent line
  const [sr, sg, sb] = hexToRgb(wl.secondaryColor);
  doc.setFillColor(sr, sg, sb);
  doc.rect(0, 40, pageWidth, 3, 'F');

  // Body content
  doc.setTextColor(30, 30, 30);
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text('Resume Executif', 15, 58);

  doc.setFontSize(11);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(60, 60, 60);

  const metrics = [
    ['Score AEO Global', '87/100'],
    ['Citations IA detectees', '142'],
    ['Sources actives', '12'],
    ['Taux de croissance', '+23%'],
    ['Recommandations', '8 actions prioritaires'],
  ];

  let y = 70;
  for (const [label, value] of metrics) {
    doc.setFillColor(245, 245, 250);
    doc.roundedRect(15, y - 5, pageWidth - 30, 14, 3, 3, 'F');
    doc.setTextColor(60, 60, 60);
    doc.setFont('helvetica', 'normal');
    doc.text(label, 20, y + 3);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(pr, pg, pb);
    doc.text(value, pageWidth - 20, y + 3, { align: 'right' });
    y += 18;
  }

  // Section with secondary color header
  y += 10;
  doc.setFillColor(sr, sg, sb);
  doc.roundedRect(15, y - 5, pageWidth - 30, 12, 3, 3, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text('Analyse detaillee', 20, y + 3);

  y += 20;
  doc.setTextColor(60, 60, 60);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  const analysisLines = [
    'Les performances AEO du site sont en progression constante sur le dernier trimestre.',
    'Les citations IA ont augmente de 23% grace aux optimisations de contenu structurees.',
    'Le Knowledge Graph enrichi a permis une meilleure reconnaissance par les modeles IA.',
    'Les fiches Entity Passport sont conformes aux standards schema.org actuels.',
    'Recommandation : renforcer la strategie de contenu sur les requetes conversationnelles.',
  ];
  for (const line of analysisLines) {
    doc.text(`  ${line}`, 15, y);
    y += 8;
  }

  // Footer
  doc.setFillColor(pr, pg, pb);
  doc.rect(0, 280, pageWidth, 17, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.text(
    `${wl.agencyName || 'Agence'} - Rapport confidentiel - Powered by CitedBy.ai`,
    pageWidth / 2,
    289,
    { align: 'center' },
  );

  doc.save(`rapport-${(wl.agencyName || 'agence').toLowerCase().replace(/\s+/g, '-')}.pdf`);
};

type SettingsTab = 'config' | 'whitelabel';

/**
 * Configuration utilisateur simplifiee avec onglet White Label pour les agences.
 */
const SettingsPage = (): JSX.Element => {
  const { profile, patchProfile, refreshProfile } = useAuth();
  const [draft, setDraft] = useState<Profile | null>(profile);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState<string>('');
  const [scanLoading, setScanLoading] = useState<boolean>(false);
  const [scanFeedback, setScanFeedback] = useState<string>('');
  const [scanError, setScanError] = useState<string | null>(null);
  const [locationModalOpen, setLocationModalOpen] = useState<boolean>(false);
  const [locationDraft, setLocationDraft] = useState<string>('');
  const [radiusDraft, setRadiusDraft] = useState<number>(30);
  const [activeTab, setActiveTab] = useState<SettingsTab>('config');

  // White Label state
  const [wl, setWl] = useState<WhiteLabelSettings>(loadWhiteLabelSettings);
  const [wlSaved, setWlSaved] = useState<boolean>(false);
  const [logoError, setLogoError] = useState<boolean>(false);

  // Simulate plan - in demo mode, default to 'enterprise' so the tab is visible.
  // In production, this would come from profile.plan or a subscription check.
  const userPlan: string = (profile as Record<string, unknown> | null)?.plan as string ?? 'enterprise';
  const isEnterprise = userPlan === 'enterprise';

  useEffect(() => {
    setDraft(profile);
  }, [profile]);

  const savePatch = useCallback(
    async (patch: Partial<Profile>): Promise<void> => {
      if (!profile) {
        return;
      }
      setStatus('Sauvegarde...');
      const ok = await patchProfile(patch);
      if (!ok) {
        setError('Erreur de sauvegarde.');
        setStatus('');
        return;
      }
      setError(null);
      setStatus('Sauvegarde');
      window.setTimeout(() => setStatus(''), 900);
    },
    [patchProfile, profile],
  );

  const debouncedSave = useMemo(
    () =>
      debounce((patch: Partial<Profile>) => {
        void savePatch(patch);
      }, 500),
    [savePatch],
  );

  if (!draft || !profile) {
    return (
      <div className="px-4 md:px-0">
        <div className="h-24 animate-pulse rounded-2xl border border-leadradar-border bg-leadradar-card" />
      </div>
    );
  }

  const creditsBalance = Number(draft.credits_balance ?? 0);
  const creditsSpent = Number(draft.credits_total_spent ?? 0);
  const creditsPurchased = Number(draft.credits_total_purchased ?? 0);
  const creditCostPerLead = Math.max(1, Number(draft.credit_cost_per_prospect ?? 1));
  const autoRechargeThreshold = Math.max(0, Number(draft.auto_recharge_trigger_threshold ?? 3));
  const autoRechargeMaxMonth = Math.max(1, Number(draft.auto_recharge_max_per_month ?? 3));
  const autoRechargeCountMonth = Math.max(0, Number(draft.auto_recharge_count_month ?? 0));
  const automationMinScore = Math.max(0, Math.min(100, Number(draft.automation_min_score ?? 80)));
  const automationDailyLimit = Math.max(1, Number(draft.automation_daily_email_limit ?? 5));
  const sectorTargets = getProfileSectorTargets(draft);

  const consumptionPercent = Math.min(100, (creditsSpent / Math.max(1, creditsPurchased)) * 100);
  const estimLeadsRemaining = Math.floor(creditsBalance / creditCostPerLead);

  const runManualScan = useCallback(async (): Promise<void> => {
    if (!profile) {
      return;
    }

    setScanLoading(true);
    setScanError(null);
    setScanFeedback('');

    try {
      if (!isSupabaseConfigured) {
        throw new Error('Supabase non configure. Ajoutez VITE_SUPABASE_URL et VITE_SUPABASE_ANON_KEY pour lancer un scan reel.');
      }

      const { data, error: invokeError } = await supabase.functions.invoke('scan-now', {
        body: {
          user_id: profile.id,
          max_sources: 12,
        },
      });

      if (invokeError) {
        throw invokeError;
      }

      const response = (data ?? {}) as ScanNowResponse;
      const triggered = Math.max(0, Number(response.triggered_sources ?? 0));
      const failed = Math.max(0, Number(response.failed_sources ?? 0));
      const fallback = Math.max(0, Number(response.fallback_direct_ingest ?? 0));

      const parts = [`Scan lance sur ${triggered} source(s)`];
      if (failed > 0) {
        parts.push(`${failed} en echec`);
      }
      if (fallback > 0) {
        parts.push(`${fallback} via pipeline direct`);
      }
      setScanFeedback(parts.join(' | '));
      await refreshProfile();
    } catch (caughtError) {
      const message = caughtError instanceof Error ? caughtError.message : 'Lancement du scan impossible';
      setScanError(message);
    } finally {
      setScanLoading(false);
    }
  }, [profile, refreshProfile]);

  const handleSaveWhiteLabel = (): void => {
    saveWhiteLabelSettings(wl);
    setWlSaved(true);
    window.setTimeout(() => setWlSaved(false), 2500);
  };

  const handleExportPdf = (): void => {
    generateBrandedPdf(wl);
  };

  // Build tabs list
  const tabs: Array<{ id: SettingsTab; label: string; icon: React.ReactNode }> = [
    { id: 'config', label: 'Configuration', icon: <Settings size={16} /> },
  ];
  if (isEnterprise) {
    tabs.push({ id: 'whitelabel', label: 'White Label', icon: <Paintbrush size={16} /> });
  }

  return (
    <div className="space-y-6 px-4 pb-24 md:max-w-6xl md:px-0 md:pb-0">
      <header className="flex flex-wrap items-end justify-between gap-3">
        <div>
          <h1 className="font-outfit text-3xl font-semibold tracking-tight">Configuration</h1>
          <p className="mt-1 text-sm text-slate-300">Recharge, ciblage, automatisation. Simple et fluide.</p>
        </div>
        <div className="flex items-center gap-3">
          {isEnterprise ? (
            <span className="inline-flex items-center gap-1.5 rounded-full bg-purple-500/15 px-3 py-1 text-xs font-semibold text-purple-400">
              <Crown size={12} />
              Agency
            </span>
          ) : null}
          {status ? <span className="rounded-full bg-emerald-500/15 px-3 py-1 text-xs text-emerald-300">{status}</span> : null}
        </div>
      </header>

      {/* Tab navigation */}
      {tabs.length > 1 ? (
        <nav className="flex gap-1 rounded-xl border border-white/5 bg-[#1a1d21] p-1">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              type="button"
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 rounded-lg px-4 py-2.5 text-sm font-medium transition-all ${
                activeTab === tab.id
                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg shadow-purple-500/20'
                  : 'text-slate-400 hover:bg-white/5 hover:text-slate-200'
              }`}
            >
              {tab.icon}
              {tab.label}
            </button>
          ))}
        </nav>
      ) : null}

      {error ? <div className="rounded-xl border border-red-500/40 bg-red-500/10 p-3 text-sm text-red-300">{error}</div> : null}

      {/* ====================== TAB: Configuration ====================== */}
      {activeTab === 'config' ? (
        <>
          <section className="grid gap-4 xl:grid-cols-2">
            <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
              <h2 className="font-outfit text-lg font-semibold">1. Recharge credits</h2>
              <p className="mt-3 text-sm text-slate-300">Solde: {creditsBalance} credits</p>
              <p className="text-sm text-slate-300">Cout par fiche: {creditCostPerLead} credit</p>
              <p className="text-sm text-slate-300">Fiches disponibles maintenant: {estimLeadsRemaining}</p>
              <p className="mt-1 text-xs text-slate-400">
                Consommes: {creditsSpent} | Achetes: {creditsPurchased}
              </p>
              <div className="mt-3 h-2 w-full rounded-full bg-slate-800">
                <div className="h-full rounded-full bg-emerald-500" style={{ width: `${consumptionPercent}%` }} />
              </div>
              <button
                type="button"
                onClick={() => {
                  if (!isSupabaseConfigured) {
                    setError('Mode demo: portail Stripe indisponible sans configuration Supabase.');
                    return;
                  }
                  void supabase.functions.invoke('customer-portal', { body: { user_id: profile.id } }).then(({ data }) => {
                    const url = String((data as { url?: string } | null)?.url ?? '');
                    if (url) {
                      window.location.href = url;
                    }
                  });
                }}
                className="mt-4 rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
              >
                Historique paiements (Stripe)
              </button>
              <div className="mt-4">
                <CreditPacks userId={profile.id} />
              </div>
            </article>

            <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
              <h2 className="font-outfit text-lg font-semibold">2. Auto-recharge</h2>
              <p className="mt-1 text-sm text-slate-300">
                Recharge automatique declenchee quand le solde passe sous un seuil.
              </p>
              <div className="mt-4 space-y-3">
                <label className="flex items-center justify-between text-sm">
                  Activer auto-recharge
                  <input
                    type="checkbox"
                    checked={Boolean(draft.auto_recharge_enabled)}
                    onChange={(event) => {
                      const value = event.target.checked;
                      setDraft((current) => (current ? { ...current, auto_recharge_enabled: value } : current));
                      debouncedSave({ auto_recharge_enabled: value });
                    }}
                  />
                </label>

                <label className="block text-sm text-slate-300">
                  Pack utilise
                  <select
                    value={(draft.auto_recharge_pack_id ?? 'pack_50') as CreditPackId}
                    onChange={(event) => {
                      const value = event.target.value as CreditPackId;
                      setDraft((current) => (current ? { ...current, auto_recharge_pack_id: value } : current));
                      debouncedSave({ auto_recharge_pack_id: value });
                    }}
                    className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
                  >
                    {CREDIT_PACKS.map((pack) => (
                      <option key={pack.id} value={pack.id}>
                        {pack.label} ({pack.credits + pack.bonusCredits} credits)
                      </option>
                    ))}
                  </select>
                </label>

                <label className="block text-sm text-slate-300">
                  Seuil de declenchement: {autoRechargeThreshold} credit(s)
                  <input
                    type="range"
                    min="1"
                    max="30"
                    value={autoRechargeThreshold}
                    onChange={(event) => {
                      const value = Number(event.target.value);
                      setDraft((current) => (current ? { ...current, auto_recharge_trigger_threshold: value } : current));
                      debouncedSave({ auto_recharge_trigger_threshold: value });
                    }}
                    className="mt-2 w-full"
                  />
                </label>

                <label className="block text-sm text-slate-300">
                  Limite auto-recharges / mois
                  <input
                    type="number"
                    min="1"
                    max="20"
                    value={autoRechargeMaxMonth}
                    onChange={(event) => {
                      const value = Math.max(1, Math.min(20, Number(event.target.value) || 1));
                      setDraft((current) => (current ? { ...current, auto_recharge_max_per_month: value } : current));
                      debouncedSave({ auto_recharge_max_per_month: value });
                    }}
                    className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
                  />
                </label>

                <p className="text-xs text-slate-400">
                  Deja utilises ce mois: {autoRechargeCountMonth} / {autoRechargeMaxMonth}
                </p>
              </div>
            </article>
          </section>

          <section className="grid gap-4 xl:grid-cols-2">
            <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
              <h2 className="font-outfit text-lg font-semibold">3. Ciblage recherche</h2>
              <p className="mt-3 text-sm text-slate-300">
                Secteurs cibles: {sectorTargets.length > 0 ? `${sectorTargets.length} selection(s)` : 'non defini'}
              </p>
              <div className="mt-3">
                <SectorTargetingSelector
                  value={sectorTargets}
                  onChange={(nextTargets) => {
                    const patch = buildProfileSectorPatch(draft, nextTargets);
                    setDraft((current) => (current ? { ...current, ...patch } : current));
                    debouncedSave(patch);
                  }}
                  maxSelections={25}
                />
              </div>
              <div className="mt-3 flex flex-wrap items-center gap-2">
                <button
                  type="button"
                  disabled={scanLoading || sectorTargets.length === 0}
                  onClick={() => {
                    void runManualScan();
                  }}
                  className="rounded-lg bg-emerald-500 px-3 py-2 text-sm font-semibold text-emerald-950 transition hover:bg-emerald-400 disabled:cursor-not-allowed disabled:opacity-60"
                >
                  {scanLoading ? 'Scan en cours...' : 'Scanner maintenant'}
                </button>
                <p className="text-xs text-slate-400">Declenche un scan immediat des sources actives pour vos secteurs.</p>
              </div>
              {scanFeedback ? <p className="mt-2 text-xs text-emerald-300">{scanFeedback}</p> : null}
              {scanError ? <p className="mt-2 text-xs text-red-300">{scanError}</p> : null}
              <p className="text-sm text-slate-300">
                Zone: {draft.location_label ?? 'Aucune ville'} | Rayon: {draft.geo_radius_km} km
              </p>
              <button
                type="button"
                onClick={() => {
                  setLocationDraft(draft.location_label ?? '');
                  setRadiusDraft(draft.geo_radius_km);
                  setLocationModalOpen(true);
                }}
                className="mt-3 rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
              >
                Modifier la zone
              </button>

              <div className="mt-4">
                <label className="text-sm text-slate-300">Score minimum: {draft.min_score}/100</label>
                <input
                  type="range"
                  min="0"
                  max="100"
                  value={draft.min_score}
                  onChange={(event) => {
                    const value = Number(event.target.value);
                    setDraft((current) => (current ? { ...current, min_score: value } : current));
                    debouncedSave({ min_score: value });
                  }}
                  className="mt-2 w-full"
                />
              </div>
              <Link
                to="/sources"
                className="mt-3 inline-flex rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
              >
                Ajuster les sources
              </Link>
            </article>

            <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
              <h2 className="font-outfit text-lg font-semibold">4. Automatisation prospection</h2>
              <p className="mt-1 text-sm text-slate-300">
                Sur prospects eligibles et credits disponibles, l app peut envoyer un email automatiquement.
              </p>
              <div className="mt-4 space-y-3">
                <label className="flex items-center justify-between text-sm">
                  Activer automatisation
                  <input
                    type="checkbox"
                    checked={Boolean(draft.automation_enabled)}
                    onChange={(event) => {
                      const value = event.target.checked;
                      setDraft((current) => (current ? { ...current, automation_enabled: value } : current));
                      debouncedSave({ automation_enabled: value });
                    }}
                  />
                </label>

                <label className="flex items-center justify-between text-sm">
                  Envoyer email prospect automatiquement
                  <input
                    type="checkbox"
                    checked={Boolean(draft.automation_send_email)}
                    onChange={(event) => {
                      const value = event.target.checked;
                      setDraft((current) => (current ? { ...current, automation_send_email: value } : current));
                      debouncedSave({ automation_send_email: value });
                    }}
                  />
                </label>

                <label className="block text-sm text-slate-300">
                  Score minimum automatisation: {automationMinScore}
                  <input
                    type="range"
                    min="50"
                    max="100"
                    value={automationMinScore}
                    onChange={(event) => {
                      const value = Number(event.target.value);
                      setDraft((current) => (current ? { ...current, automation_min_score: value } : current));
                      debouncedSave({ automation_min_score: value });
                    }}
                    className="mt-2 w-full"
                  />
                </label>

                <label className="block text-sm text-slate-300">
                  Limite d emails auto / jour
                  <input
                    type="number"
                    min="1"
                    max="100"
                    value={automationDailyLimit}
                    onChange={(event) => {
                      const value = Math.max(1, Math.min(100, Number(event.target.value) || 1));
                      setDraft((current) => (current ? { ...current, automation_daily_email_limit: value } : current));
                      debouncedSave({ automation_daily_email_limit: value });
                    }}
                    className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
                  />
                </label>

                <label className="block text-sm text-slate-300">
                  Sujet email auto
                  <input
                    type="text"
                    value={draft.automation_email_subject_template ?? ''}
                    onChange={(event) => {
                      const value = event.target.value.slice(0, 160);
                      setDraft((current) => (current ? { ...current, automation_email_subject_template: value } : current));
                      debouncedSave({ automation_email_subject_template: value });
                    }}
                    className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
                    placeholder="Ex: Opportunite detectee pour {{prospect_name}}"
                  />
                </label>

                <label className="block text-sm text-slate-300">
                  Signature email auto
                  <textarea
                    value={draft.automation_email_signature ?? ''}
                    onChange={(event) => {
                      const value = event.target.value.slice(0, 600);
                      setDraft((current) => (current ? { ...current, automation_email_signature: value } : current));
                      debouncedSave({ automation_email_signature: value });
                    }}
                    rows={3}
                    className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
                    placeholder="Ex: Bien cordialement, ..."
                  />
                </label>

                <p className="text-xs text-slate-400">
                  Envoyes aujourd hui: {Math.max(0, Number(draft.automation_emails_sent_today ?? 0))} / {automationDailyLimit}
                </p>
              </div>
            </article>
          </section>

          <section className="grid gap-4 xl:grid-cols-2">
            <article className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
              <h2 className="font-outfit text-lg font-semibold">5. Alertes</h2>
              <div className="mt-3 space-y-2 text-sm">
                <label className="flex items-center justify-between">
                  Email
                  <input
                    type="checkbox"
                    checked={draft.notification_email}
                    onChange={(event) => {
                      const value = event.target.checked;
                      setDraft((current) => (current ? { ...current, notification_email: value } : current));
                      debouncedSave({ notification_email: value });
                    }}
                  />
                </label>
                <label className="flex items-center justify-between">
                  Push
                  <input
                    type="checkbox"
                    checked={draft.notification_push}
                    onChange={(event) => {
                      const value = event.target.checked;
                      setDraft((current) => (current ? { ...current, notification_push: value } : current));
                      debouncedSave({ notification_push: value });
                    }}
                  />
                </label>
                <label className="flex items-center justify-between">
                  Brulants uniquement
                  <input
                    type="checkbox"
                    checked={draft.burning_only_alerts}
                    onChange={(event) => {
                      const value = event.target.checked;
                      setDraft((current) => (current ? { ...current, burning_only_alerts: value } : current));
                      debouncedSave({ burning_only_alerts: value });
                    }}
                  />
                </label>
              </div>
            </article>

            <details className="rounded-2xl border border-leadradar-border bg-leadradar-card p-5">
              <summary className="cursor-pointer font-outfit text-lg font-semibold">6. Parametres avances</summary>
              <div className="mt-4 space-y-4">
                <div>
                  <label className="text-sm text-slate-300">Frequence de scan</label>
                  <select
                    value={draft.scan_frequency_hours}
                    onChange={(event) => {
                      const value = Number(event.target.value);
                      setDraft((current) => (current ? { ...current, scan_frequency_hours: value } : current));
                      debouncedSave({ scan_frequency_hours: value });
                    }}
                    className="mt-2 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2 text-sm"
                  >
                    <option value={2}>Toutes les 2h</option>
                    <option value={6}>Toutes les 6h</option>
                    <option value={12}>Toutes les 12h</option>
                    <option value={24}>Toutes les 24h</option>
                  </select>
                </div>

                <div>
                  <label className="text-sm text-slate-300">Ton des messages</label>
                  <div className="mt-2 grid gap-2 md:grid-cols-3">
                    {([
                      ['professional', 'Professionnel'],
                      ['friendly', 'Amical'],
                      ['direct', 'Direct'],
                    ] as Array<[ApproachTone, string]>).map(([tone, label]) => (
                      <label
                        key={tone}
                        className={`rounded-lg border p-3 text-sm ${
                          draft.approach_tone === tone ? 'border-emerald-500 bg-emerald-500/10' : 'border-leadradar-border bg-[#0F172A]'
                        }`}
                      >
                        <input
                          type="radio"
                          name="approach-tone"
                          checked={draft.approach_tone === tone}
                          onChange={() => {
                            setDraft((current) => (current ? { ...current, approach_tone: tone } : current));
                            debouncedSave({ approach_tone: tone });
                          }}
                          className="mr-2"
                        />
                        {label}
                        <p className="mt-2 text-xs text-slate-300">{TONE_PREVIEWS[tone]}</p>
                      </label>
                    ))}
                  </div>
                </div>
              </div>
            </details>
          </section>
        </>
      ) : null}

      {/* ====================== TAB: White Label ====================== */}
      {activeTab === 'whitelabel' && isEnterprise ? (
        <div className="space-y-6 animate-slide-in">
          {/* Header description */}
          <div className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5">
            <div className="flex items-center gap-3">
              <div className="grid h-10 w-10 place-items-center rounded-xl bg-gradient-to-br from-purple-500 to-violet-600">
                <Paintbrush size={20} className="text-white" />
              </div>
              <div>
                <h2 className="font-outfit text-lg font-semibold">Personnalisation White Label</h2>
                <p className="text-sm text-slate-400">
                  Personnalisez votre branding agence pour vos rapports et interfaces client.
                </p>
              </div>
            </div>
          </div>

          <div className="grid gap-6 xl:grid-cols-2">
            {/* Left column: Form */}
            <div className="space-y-4">
              {/* Logo URL */}
              <article className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5">
                <div className="flex items-center gap-2 mb-4">
                  <Image size={16} className="text-purple-400" />
                  <h3 className="font-outfit text-sm font-semibold text-slate-200">Logo de l'agence</h3>
                </div>
                <label className="block text-sm text-slate-300">
                  URL du logo
                  <input
                    type="text"
                    value={wl.logoUrl}
                    onChange={(e) => {
                      setWl((prev) => ({ ...prev, logoUrl: e.target.value }));
                      setLogoError(false);
                    }}
                    className="mt-1 w-full rounded-lg border border-white/5 bg-[#0F172A] px-3 py-2.5 text-sm text-white placeholder-slate-500 focus:border-purple-500/50 focus:outline-none focus:ring-1 focus:ring-purple-500/30"
                    placeholder="https://example.com/logo.png"
                  />
                </label>
                {wl.logoUrl ? (
                  <div className="mt-3 flex items-center gap-3">
                    <div className="h-16 w-16 overflow-hidden rounded-xl border border-white/5 bg-white/5 p-1">
                      {!logoError ? (
                        <img
                          src={wl.logoUrl}
                          alt="Logo preview"
                          className="h-full w-full object-contain"
                          onError={() => setLogoError(true)}
                        />
                      ) : (
                        <div className="flex h-full w-full items-center justify-center text-xs text-red-400">Erreur</div>
                      )}
                    </div>
                    <span className="text-xs text-slate-400">Apercu du logo</span>
                  </div>
                ) : null}
              </article>

              {/* Agency name */}
              <article className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5">
                <div className="flex items-center gap-2 mb-4">
                  <Building2 size={16} className="text-purple-400" />
                  <h3 className="font-outfit text-sm font-semibold text-slate-200">Nom de l'agence</h3>
                </div>
                <label className="block text-sm text-slate-300">
                  Nom affiche dans les rapports
                  <input
                    type="text"
                    value={wl.agencyName}
                    onChange={(e) => setWl((prev) => ({ ...prev, agencyName: e.target.value.slice(0, 100) }))}
                    className="mt-1 w-full rounded-lg border border-white/5 bg-[#0F172A] px-3 py-2.5 text-sm text-white placeholder-slate-500 focus:border-purple-500/50 focus:outline-none focus:ring-1 focus:ring-purple-500/30"
                    placeholder="Mon Agence AEO"
                  />
                </label>
              </article>

              {/* Colors */}
              <article className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5">
                <div className="flex items-center gap-2 mb-4">
                  <Palette size={16} className="text-purple-400" />
                  <h3 className="font-outfit text-sm font-semibold text-slate-200">Couleurs de la marque</h3>
                </div>
                <div className="grid gap-4 sm:grid-cols-2">
                  {/* Primary color */}
                  <div>
                    <label className="block text-sm text-slate-300 mb-1.5">Couleur primaire</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        value={wl.primaryColor}
                        onChange={(e) => setWl((prev) => ({ ...prev, primaryColor: e.target.value }))}
                        className="h-10 w-10 cursor-pointer rounded-lg border border-white/5 bg-transparent p-0.5"
                      />
                      <input
                        type="text"
                        value={wl.primaryColor}
                        onChange={(e) => {
                          const val = e.target.value;
                          if (/^#[0-9a-fA-F]{0,6}$/.test(val) || val === '') {
                            setWl((prev) => ({ ...prev, primaryColor: val || '#' }));
                          }
                        }}
                        className="w-full rounded-lg border border-white/5 bg-[#0F172A] px-3 py-2 text-sm text-white font-mono focus:border-purple-500/50 focus:outline-none focus:ring-1 focus:ring-purple-500/30"
                        placeholder="#a855f7"
                        maxLength={7}
                      />
                    </div>
                    <div
                      className="mt-2 h-3 rounded-full"
                      style={{ backgroundColor: wl.primaryColor }}
                    />
                  </div>
                  {/* Secondary color */}
                  <div>
                    <label className="block text-sm text-slate-300 mb-1.5">Couleur secondaire</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        value={wl.secondaryColor}
                        onChange={(e) => setWl((prev) => ({ ...prev, secondaryColor: e.target.value }))}
                        className="h-10 w-10 cursor-pointer rounded-lg border border-white/5 bg-transparent p-0.5"
                      />
                      <input
                        type="text"
                        value={wl.secondaryColor}
                        onChange={(e) => {
                          const val = e.target.value;
                          if (/^#[0-9a-fA-F]{0,6}$/.test(val) || val === '') {
                            setWl((prev) => ({ ...prev, secondaryColor: val || '#' }));
                          }
                        }}
                        className="w-full rounded-lg border border-white/5 bg-[#0F172A] px-3 py-2 text-sm text-white font-mono focus:border-purple-500/50 focus:outline-none focus:ring-1 focus:ring-purple-500/30"
                        placeholder="#7c3aed"
                        maxLength={7}
                      />
                    </div>
                    <div
                      className="mt-2 h-3 rounded-full"
                      style={{ backgroundColor: wl.secondaryColor }}
                    />
                  </div>
                </div>
              </article>

              {/* Custom Domain - Coming Soon */}
              <article className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5 opacity-60">
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <Globe size={16} className="text-purple-400" />
                    <h3 className="font-outfit text-sm font-semibold text-slate-200">Domaine personnalise</h3>
                  </div>
                  <span className="rounded-full bg-purple-500/15 px-2.5 py-0.5 text-[10px] font-bold uppercase tracking-wider text-purple-400">
                    Coming Soon
                  </span>
                </div>
                <p className="text-xs text-slate-400">
                  Connectez votre propre domaine pour offrir a vos clients une experience 100% brandee.
                </p>
                <input
                  type="text"
                  disabled
                  className="mt-3 w-full rounded-lg border border-white/5 bg-[#0F172A] px-3 py-2.5 text-sm text-slate-500 cursor-not-allowed"
                  placeholder="app.mon-agence.com"
                />
              </article>

              {/* Actions */}
              <div className="flex flex-wrap items-center gap-3">
                <button
                  type="button"
                  onClick={handleSaveWhiteLabel}
                  className="inline-flex items-center gap-2 rounded-xl bg-gradient-to-r from-purple-500 to-violet-600 px-5 py-2.5 text-sm font-semibold text-white shadow-lg shadow-purple-500/25 transition hover:shadow-purple-500/40 hover:brightness-110"
                >
                  {wlSaved ? <Check size={16} /> : <Save size={16} />}
                  {wlSaved ? 'Sauvegarde !' : 'Sauvegarder'}
                </button>
                <button
                  type="button"
                  onClick={handleExportPdf}
                  className="inline-flex items-center gap-2 rounded-xl border border-white/5 bg-[#1a1d21] px-5 py-2.5 text-sm font-medium text-slate-200 transition hover:border-purple-500/30 hover:text-purple-400"
                >
                  <FileDown size={16} />
                  Exporter rapport PDF brande
                </button>
              </div>

              {/* Success toast */}
              {wlSaved ? (
                <div className="rounded-xl border border-emerald-500/30 bg-emerald-500/10 p-3 text-sm text-emerald-300 flex items-center gap-2">
                  <Check size={16} />
                  Parametres White Label sauvegardes avec succes.
                </div>
              ) : null}
            </div>

            {/* Right column: Live Preview */}
            <div className="space-y-4">
              <article className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5">
                <div className="flex items-center gap-2 mb-4">
                  <Eye size={16} className="text-purple-400" />
                  <h3 className="font-outfit text-sm font-semibold text-slate-200">Apercu en direct</h3>
                </div>

                {/* Mini dashboard preview */}
                <div className="rounded-xl border border-white/5 bg-[#0d1017] overflow-hidden">
                  {/* Preview header */}
                  <div
                    className="flex items-center gap-3 px-4 py-3"
                    style={{ backgroundColor: wl.primaryColor }}
                  >
                    {wl.logoUrl && !logoError ? (
                      <img
                        src={wl.logoUrl}
                        alt="Logo"
                        className="h-7 w-7 rounded-md object-contain bg-white/20 p-0.5"
                        onError={() => setLogoError(true)}
                      />
                    ) : (
                      <div className="h-7 w-7 rounded-md bg-white/20 grid place-items-center text-[10px] font-bold text-white">
                        {(wl.agencyName || 'A').charAt(0).toUpperCase()}
                      </div>
                    )}
                    <span className="text-sm font-semibold text-white">
                      {wl.agencyName || 'Nom Agence'}
                    </span>
                  </div>

                  {/* Preview accent bar */}
                  <div className="h-1" style={{ backgroundColor: wl.secondaryColor }} />

                  {/* Preview body */}
                  <div className="p-4 space-y-3">
                    {/* Stats row */}
                    <div className="grid grid-cols-3 gap-2">
                      {[
                        { label: 'Score AEO', value: '87' },
                        { label: 'Citations', value: '142' },
                        { label: 'Sources', value: '12' },
                      ].map((stat) => (
                        <div
                          key={stat.label}
                          className="rounded-lg border border-white/5 bg-white/[0.02] p-2 text-center"
                        >
                          <div
                            className="text-lg font-bold"
                            style={{ color: wl.primaryColor }}
                          >
                            {stat.value}
                          </div>
                          <div className="text-[10px] text-slate-400">{stat.label}</div>
                        </div>
                      ))}
                    </div>

                    {/* Progress bar */}
                    <div>
                      <div className="flex items-center justify-between text-[10px] text-slate-400 mb-1">
                        <span>Progression AEO</span>
                        <span>87%</span>
                      </div>
                      <div className="h-2 w-full rounded-full bg-white/5">
                        <div
                          className="h-full rounded-full transition-all"
                          style={{
                            width: '87%',
                            background: `linear-gradient(to right, ${wl.primaryColor}, ${wl.secondaryColor})`,
                          }}
                        />
                      </div>
                    </div>

                    {/* Mock table rows */}
                    <div className="space-y-1.5">
                      {['Optimisation schema.org', 'Content IA structuree', 'Knowledge Graph'].map(
                        (item, i) => (
                          <div
                            key={item}
                            className="flex items-center justify-between rounded-lg border border-white/5 bg-white/[0.02] px-3 py-2"
                          >
                            <span className="text-[11px] text-slate-300">{item}</span>
                            <span
                              className="rounded-full px-2 py-0.5 text-[10px] font-semibold"
                              style={{
                                backgroundColor: `${i === 0 ? wl.primaryColor : wl.secondaryColor}20`,
                                color: i === 0 ? wl.primaryColor : wl.secondaryColor,
                              }}
                            >
                              {i === 0 ? 'Complet' : i === 1 ? 'En cours' : 'A faire'}
                            </span>
                          </div>
                        ),
                      )}
                    </div>

                    {/* Button preview */}
                    <button
                      type="button"
                      className="w-full rounded-lg py-2 text-xs font-semibold text-white transition"
                      style={{
                        background: `linear-gradient(to right, ${wl.primaryColor}, ${wl.secondaryColor})`,
                      }}
                    >
                      Generer un rapport
                    </button>
                  </div>

                  {/* Preview footer */}
                  <div
                    className="px-4 py-2 text-center text-[9px] text-white/60"
                    style={{ backgroundColor: wl.primaryColor + '30' }}
                  >
                    Powered by {wl.agencyName || 'Votre Agence'} &middot; CitedBy.ai
                  </div>
                </div>
              </article>

              {/* PDF Preview card */}
              <article className="rounded-2xl border border-white/5 bg-[#1a1d21] p-5">
                <div className="flex items-center gap-2 mb-4">
                  <FileDown size={16} className="text-purple-400" />
                  <h3 className="font-outfit text-sm font-semibold text-slate-200">Apercu rapport PDF</h3>
                </div>
                <div className="rounded-xl border border-white/5 bg-white overflow-hidden">
                  {/* PDF Header simulation */}
                  <div
                    className="px-4 py-3"
                    style={{ backgroundColor: wl.primaryColor }}
                  >
                    <div className="text-sm font-bold text-white">{wl.agencyName || 'Agence'}</div>
                    <div className="text-[10px] text-white/70">Rapport de performance - White Label</div>
                  </div>
                  <div className="h-1" style={{ backgroundColor: wl.secondaryColor }} />
                  <div className="p-4 space-y-2">
                    {[
                      ['Score AEO Global', '87/100'],
                      ['Citations IA', '142'],
                      ['Croissance', '+23%'],
                    ].map(([label, val]) => (
                      <div key={label} className="flex items-center justify-between rounded bg-gray-50 px-3 py-1.5">
                        <span className="text-[10px] text-gray-600">{label}</span>
                        <span
                          className="text-[10px] font-bold"
                          style={{ color: wl.primaryColor }}
                        >
                          {val}
                        </span>
                      </div>
                    ))}
                  </div>
                  <div
                    className="px-4 py-1.5 text-center text-[8px]"
                    style={{ backgroundColor: wl.primaryColor, color: 'rgba(255,255,255,0.8)' }}
                  >
                    {wl.agencyName || 'Agence'} - Powered by CitedBy.ai
                  </div>
                </div>
              </article>
            </div>
          </div>
        </div>
      ) : null}

      {locationModalOpen ? (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
          <div className="w-full max-w-md rounded-2xl border border-leadradar-border bg-[#111827] p-5">
            <h3 className="font-outfit text-lg font-semibold">Zone geographique</h3>
            <label className="mt-3 block text-sm">
              Ville
              <input
                value={locationDraft}
                onChange={(event) => setLocationDraft(event.target.value)}
                className="mt-1 w-full rounded-lg border border-leadradar-border bg-[#0F172A] px-3 py-2"
                placeholder="Paris, Ile-de-France"
              />
            </label>
            <label className="mt-3 block text-sm">
              Rayon: {radiusDraft} km
              <input
                type="range"
                min="5"
                max="100"
                value={radiusDraft}
                onChange={(event) => setRadiusDraft(Number(event.target.value))}
                className="mt-2 w-full"
              />
            </label>
            <div className="mt-4 flex justify-end gap-2">
              <button
                type="button"
                onClick={() => setLocationModalOpen(false)}
                className="rounded-lg border border-leadradar-border px-3 py-2 text-sm"
              >
                Annuler
              </button>
              <button
                type="button"
                onClick={() => {
                  const patch: Partial<Profile> = {
                    location_label: locationDraft.trim() || null,
                    geo_radius_km: radiusDraft,
                  };
                  setDraft((current) => (current ? { ...current, ...patch } : current));
                  void savePatch(patch);
                  setLocationModalOpen(false);
                }}
                className="rounded-lg bg-emerald-500 px-3 py-2 text-sm font-semibold text-emerald-950"
              >
                Enregistrer
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
};

export default SettingsPage;

