import { useCallback, useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import { CreditPacks } from '../components/settings/credit-packs';
import { SectorTargetingSelector } from '../components/shared/sector-targeting-selector';
import { useAuth } from '../hooks/useAuth';
import { CREDIT_PACKS } from '../lib/constants';
import { isSupabaseConfigured, supabase } from '../lib/supabase';
import type { ApproachTone, CreditPackId, Profile } from '../lib/types';
import { buildProfileSectorPatch, getProfileSectorTargets } from '../utils/sector-targeting';
import { debounce } from '../utils/debounce';
import {
  Settings,
  Paintbrush,
  Image,
  Building2,
  Palette,
  FileDown,
  Globe,
  Save,
  Check,
  Crown,
