interface WhiteLabelSettings {
  logoUrl: string;
  agencyName: string;
  primaryColor: string;
  secondaryColor: string;
}

const WL_STORAGE_KEY = 'citedby-whitelabel';

const loadWhiteLabelSettings = (): WhiteLabelSettings => {
  try {
    const raw = window.localStorage.getItem(WL_STORAGE_KEY);
    if (raw) {
      return JSON.parse(raw) as WhiteLabelSettings;
    }
  } catch {
    // ignore parse errors
  }
  return {
    logoUrl: '',
    agencyName: '',
    primaryColor: '#a855f7',
    secondaryColor: '#7c3aed',
  };
};

const saveWhiteLabelSettings = (settings: WhiteLabelSettings): void => {
  window.localStorage.setItem(WL_STORAGE_KEY, JSON.stringify(settings));
};

/**
 * Hex color to RGB helper for jsPDF.
 */
const hexToRgb = (hex: string): [number, number, number] => {
  const clean = hex.replace('#', '');
  const r = parseInt(clean.substring(0, 2), 16) || 0;
  const g = parseInt(clean.substring(2, 4), 16) || 0;
  const b = parseInt(clean.substring(4, 6), 16) || 0;
  return [r, g, b];
};

/**
 * Generate branded PDF report.
 */
const generateBrandedPdf = (wl: WhiteLabelSettings): void => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();

  // Header bar with primary color
  const [pr, pg, pb] = hexToRgb(wl.primaryColor);
  doc.setFillColor(pr, pg, pb);
  doc.rect(0, 0, pageWidth, 40, 'F');

  // Agency name in header
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text(wl.agencyName || 'Agence', 15, 18);

  // Subtitle
  doc.setFontSize(11);
  doc.setFont('helvetica', 'normal');
  doc.text('Rapport de performance - White Label', 15, 28);

  // Date
  doc.setFontSize(9);
  doc.text('Genere le ' + new Date().toLocaleDateString('fr-FR'), 15, 35);

  // Secondary color accent line
  const [sr, sg, sb] = hexToRgb(wl.secondaryColor);
  doc.setFillColor(sr, sg, sb);
  doc.rect(0, 40, pageWidth, 3, 'F');

  // Body content
  doc.setTextColor(30, 30, 30);
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text('Resume Executif', 15, 58);

  doc.setFontSize(11);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(60, 60, 60);

  const metrics: Array<[string, string]> = [
    ['Score AEO Global', '87/100'],
    ['Citations IA detectees', '142'],
    ['Sources actives', '12'],
    ['Taux de croissance', '+23%'],
    ['Recommandations', '8 actions prioritaires'],
  ];

  let y = 70;
  for (const [label, value] of metrics) {
    doc.setFillColor(245, 245, 250);
    doc.roundedRect(15, y - 5, pageWidth - 30, 14, 3, 3, 'F');
    doc.setTextColor(60, 60, 60);
    doc.setFont('helvetica', 'normal');
    doc.text(label, 20, y + 3);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(pr, pg, pb);
    doc.text(value, pageWidth - 20, y + 3, { align: 'right' });
    y += 18;
  }

  // Section with secondary color header
  y += 10;
  doc.setFillColor(sr, sg, sb);
  doc.roundedRect(15, y - 5, pageWidth - 30, 12, 3, 3, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text('Analyse detaillee', 20, y + 3);

  y += 20;
  doc.setTextColor(60, 60, 60);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  const analysisLines = [
    'Les performances AEO du site sont en progression constante sur le dernier trimestre.',
    'Les citations IA ont augmente de 23% grace aux optimisations de contenu structurees.',
    'Le Knowledge Graph enrichi a permis une meilleure reconnaissance par les modeles IA.',
    'Les fiches Entity Passport sont conformes aux standards schema.org actuels.',
    'Recommandation : renforcer la strategie de contenu sur les requetes conversationnelles.',
  ];
  for (const line of analysisLines) {
    doc.text('  ' + line, 15, y);
    y += 8;
  }

  // Footer
  doc.setFillColor(pr, pg, pb);
  doc.rect(0, 280, pageWidth, 17, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.text(
    (wl.agencyName || 'Agence') + ' - Rapport confidentiel - Powered by CitedBy.ai',
    pageWidth / 2,
    289,
    { align: 'center' },
  );

  doc.save('rapport-' + (wl.agencyName || 'agence').toLowerCase().replace(/\s+/g, '-') + '.pdf');
};

