  // White Label state
  const [wl, setWl] = useState<WhiteLabelSettings>(loadWhiteLabelSettings);
  const [wlSaved, setWlSaved] = useState<boolean>(false);
  const [logoError, setLogoError] = useState<boolean>(false);

  // Simulate plan - in demo mode, default to 'enterprise' so the tab is visible.
  // In production, this would come from profile.plan or a subscription check.
  const userPlan: string = (profile as Record<string, unknown> | null)?.plan as string ?? 'enterprise';
  const isEnterprise = userPlan === 'enterprise';

  useEffect(() => {
    setDraft(profile);
  }, [profile]);

  const savePatch = useCallback(
    async (patch: Partial<Profile>): Promise<void> => {
      if (!profile) {
        return;
      }
      setStatus('Sauvegarde...');
      const ok = await patchProfile(patch);
      if (!ok) {
        setError('Erreur de sauvegarde.');
        setStatus('');
        return;
      }
      setError(null);
      setStatus('Sauvegarde');
      window.setTimeout(() => setStatus(''), 900);
    },
