      if (!isSupabaseConfigured) {
        throw new Error('Supabase non configure. Ajoutez VITE_SUPABASE_URL et VITE_SUPABASE_ANON_KEY pour lancer un scan reel.');
      }

      const { data, error: invokeError } = await supabase.functions.invoke('scan-now', {
        body: {
          user_id: profile.id,
          max_sources: 12,
