      if (invokeError) {
        throw invokeError;
      }

      const response = (data ?? {}) as ScanNowResponse;
      const triggered = Math.max(0, Number(response.triggered_sources ?? 0));
      const failed = Math.max(0, Number(response.failed_sources ?? 0));
      const fallback = Math.max(0, Number(response.fallback_direct_ingest ?? 0));

